# Base module with interface, base class, and utility function

interface Countable:
    def get_count(self) -> int: ...

class BaseCounter(Countable):
    count: int

    def __init__(self, start: int):
        self.count = start

    def get_count(self) -> int:
        return self.count

    @virtual
    def increment(self) -> int:
        self.count = self.count + 1
        return self.count

@static
MULTIPLIER: int = 2

def double_value(x: int) -> int:
    return x * MULTIPLIER

