# Derived module with class inheriting from BaseCounter
from utils import BaseCounter

class AdvancedCounter(BaseCounter):
    step: int

    def __init__(self, start: int, step: int):
        super().__init__(start)
        self.step = step

    @override
    def increment(self) -> int:
        self.count = self.count + self.step
        return self.count
